UPDATE trip_plan_items
SET item_order = #{order}
WHERE item_id = #{itemId}

UPDATE trip_plan_items
SET item_order = item_order + 1
WHERE plan_id = #{planId}
  AND day_number = #{dayNumber}
  AND item_order >= #{itemOrder}
